(function($){"use strict";const ghlBuddyBossGroup=window.ghl_buddyboss_group_meta_box_js_data||{};const GHLBuddyBossGroupMetaBox={init:function(){this.bindEvents()},bindEvents:function(){$(document).on("click","#ghl-sync-group-btn",this.handleGroupSync.bind(this),);$(document).on("click","#ghl-sync-members-btn",this.handleMembersSync.bind(this),)},handleGroupSync:function(e){e.preventDefault();const $btn=$(e.currentTarget);const groupId=$btn.data("group-id");const nonce=$btn.data("nonce");this.performSync("group",groupId,nonce,$btn)},handleMembersSync:function(e){e.preventDefault();const $btn=$(e.currentTarget);const groupId=$btn.data("group-id");const nonce=$btn.data("nonce");const groupSyncNonce=$("#ghl-sync-group-btn").data("nonce");this.performSync("members",groupId,groupSyncNonce,$btn)},performSync:function(syncType,groupId,nonce,$btn){const $spinner=$(".ghl-sync-spinner");const $message=$(".ghl-sync-message");const originalText=$btn.html();$(".ghl-sync-btn").prop("disabled",!0);$spinner.addClass("is-active").show();$message.hide();$btn.html('<span class="dashicons dashicons-update"></span> '+ghlBuddyBossGroup.strings.syncing,);$.ajax({url:ghlBuddyBossGroup.ajaxUrl,type:"POST",data:{action:"ghl_sync_buddyboss_group",group_id:groupId,sync_type:syncType,nonce:nonce,},success:function(response){if(response.success){$message.removeClass("error").addClass("success").text(response.data.message).show()}else{$message.removeClass("success").addClass("error").text(response.data.message||ghlBuddyBossGroup.strings.syncError,).show()}},error:function(){$message.removeClass("success").addClass("error").text(ghlBuddyBossGroup.strings.syncError).show()},complete:function(){$(".ghl-sync-btn").prop("disabled",!1);$spinner.removeClass("is-active").hide();$btn.html(originalText);setTimeout(function(){$message.fadeOut()},5000)},})},};$(document).ready(function(){GHLBuddyBossGroupMetaBox.init()})})(jQuery)